run.query:
#graphql
  mutation BulkOperationRunQueryGroupObjectsTrue($query: String!) {
    bulkOperationRunQuery(query: $query, groupObjects: true) {
      bulkOperation {

  id
  status
  type
  errorCode
  createdAt
  completedAt
  objectCount
  rootObjectCount
  fileSize
  url
  partialDataUrl
  query

      }
      userErrors {
        field
        message
      }
    }
  }

